  coaching_execution = '{"movement_description":"Step off low box — do not jump up — land both feet together, absorb through ankle/knee/hip, freeze 2 seconds.","setup":["Use low box or step.","Stand tall on box edge.","Athlete steps off, not jumps up.","Landing area is flat and safe.","Coach watches from front and side."],"execution_steps":["Step off box.","Let both feet contact together.","Absorb through ankle, knee, and hip.","Keep knees tracking over toes.","Freeze landing for 2 seconds.","Reset by stepping back up."],"breathing_cues":["Exhale on landing — brace trunk without holding breath."],"coach_cues":["Step off, don''t jump up.","Land quiet.","Knees over toes.","Hips back.","Freeze."],"athlete_cues":["Step.","Land quiet.","Stick it.","Freeze strong."],"common_faults":["Jumping up before dropping.","Box too high.","Knees collapsing inward.","Feet slapping.","Torso collapsing forward.","Extra hops or steps after landing."],"stop_signs":["Knee pain.","Ankle pain.","Heel pain.","Loud uncontrolled landing.","Cannot freeze landing.","Fear of dropping."]}'::jsonb,
