  coaching_execution = '{"movement_description":"Repeated two-foot hops over 2–5 low hurdles — quick ground contact, rhythm, clean clearance, stick after final hurdle.","setup":["Set 2–5 low hurdles.","Use low height appropriate to athlete.","Set spacing based on ability.","Clear area beyond final hurdle.","Start with two-foot hops."],"execution_steps":["Start tall in front of first hurdle.","Jump over first hurdle.","Land with quick contact.","Rebound over next hurdle.","Continue rhythmically.","Stick or run out safely after final hurdle."],"breathing_cues":["Stay loose through upper body — rhythm should not mean breath-holding."],"coach_cues":["Low hurdles.","Quick ground.","Pop over, don''t tuck wildly.","Stay tall.","Rhythm, rhythm, rhythm."],"athlete_cues":["Hop, pop, hop.","Quick feet.","Clear and rebound.","Stay tall."],"common_faults":["Hurdles too high.","Athlete tucks knees excessively to clear.","Ground contact too long.","Landing with knees caving.","Rhythm breaks after first hurdle.","Fatigue causes heavy contacts."],"stop_signs":["Clipping hurdles repeatedly.","Knee pain.","Achilles/calf pain.","Athlete cannot rebound cleanly.","Loud contacts.","Fear of the hurdles."]}'::jsonb,
