  ('lateral-line-hops', 'Faster contacts, single-leg progression, or lateral pogo series.', 'No default sex-based adjustment. Scale by tissue tolerance, body mass, landing history, calf/Achilles readiness, contact quality, and symptoms rather than gender alone.'),
  ('single-leg-pogo-hold-to-hop', 'Continuous single-leg pogos or directional single-leg pogos.', 'No default sex-based adjustment. Scale by tissue tolerance, body mass, landing history, calf/Achilles readiness, contact quality, and symptoms rather than gender alone.'),
  ('snap-down-to-stick', 'Add snap-down to rebound or lateral snap-down.', 'No default sex-based adjustment. Scale by tissue tolerance, body mass, landing history, calf/Achilles readiness, contact quality, and symptoms rather than gender alone.'),
  ('snap-down-to-rebound', 'Add rebound to target or low hurdle.', 'No default sex-based adjustment. Scale by tissue tolerance, body mass, landing history, calf/Achilles readiness, contact quality, and symptoms rather than gender alone.'),
  ('drop-landing-to-stick', 'Higher box only if landing quality remains excellent.', 'No default sex-based adjustment. Scale by tissue tolerance, body mass, landing history, calf/Achilles readiness, contact quality, and symptoms rather than gender alone.'),
  ('depth-drop-to-rebound', 'Low box rebound; height only increased if contact/landing quality remains excellent.', 'No default sex-based adjustment. Scale by tissue tolerance, body mass, landing history, calf/Achilles readiness, contact quality, and symptoms rather than gender alone.'),
  ('hurdle-hop-series-low-hurdles', '3–5 hurdles, faster contacts, individualized spacing.', 'No default sex-based adjustment. Scale by tissue tolerance, body mass, landing history, calf/Achilles readiness, contact quality, and symptoms rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'adult_advanced'
);

