-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('fast-low-pogos', 'Pogos are one of the simplest ways to teach lower-leg stiffness and quick elastic contacts. The Prehab Guys'' sagittal pogo reference cues bouncing on the balls of the feet, thinking of the body like a spring-loaded coil, and maintaining a stiff foot/ankle and relatively stiff legs. Fast low pogos belong early in the plyometric progression because they expose the athlete to short contact times without the larger hip/knee displacement of bigger jumps. Sportsmith describes low-amplitude plyometrics as lower-force jumping variations with low jump height, relatively quick contacts, and less knee/hip range of motion.', 'Belongs in elastic_ankle (331) — primary Output ankle stiffness entry after Prepare / Access low pogos and before directional pogo progressions.', 'First true Output elastic drill after lower-leg prep and Skill rhythm work; before directional pogos or lateral elastic drills.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Do not squat the bounce or turn into a conditioning circuit. Stop when rhythm slows or contacts get loud.', 'Regress to Prepare / Access low pogos or supported ankle bounces; progress to forward/back pogos when vertical contacts stay quiet and springy.'),
  ('forward-backward-pogos', 'Forward/backward pogos add directional control to the same ankle stiffness concept. The Prehab Guys'' sagittal pogo variation specifically cues bouncing on the balls of the feet while moving forward and backward, focusing on a stiff foot/ankle and spring-like leg action.', 'Belongs in elastic_ankle (331) — sagittal directional progression after vertical fast low pogos; small travel only.', 'After fast low pogos when vertical contacts are clean; before lateral line hops or single-leg elastic progressions.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Large bounds are separate Output cards. Do not travel too far or stomp forward/back.', 'Regress to vertical fast low pogos; progress to lateral line hops when forward/back contacts stay quick and quiet.'),
  ('lateral-line-hops', 'Lateral line hops add frontal-plane elastic control to the plyometric progression. They prepare the lower leg and hip for lateral stiffness, change-of-direction, skater bounds, and lateral deceleration. They still sit in the rudiment category because the line provides a low-height task constraint and the displacement can remain small.', 'Belongs in lateral_elastic (332) — frontal-plane elastic rudiment after bilateral pogos, before single-leg lateral progressions.', 'After basic pogos and lateral movement mechanics; before single-leg elastic or lateral power bounds.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Do not hop too far or allow knee collapse. Regress to lateral step-touch if frontal-plane control fails.', 'Regress to side step over line or small two-foot hops; progress to single-leg lateral hops only when bilateral contacts stay aligned.'),
  ('single-leg-pogo-hold-to-hop', 'Single-leg elastic work raises the balance and tissue demands significantly because the athlete must control stiffness, alignment, and contact on one limb. Sportsmith''s continuum emphasizes that true plyometrics are demanding on tendinous structures and that graded exposure to jumping and landing is important before higher-end plyometrics.', 'Belongs in single_leg_elastic (333) — single-leg progression requiring bilateral pogo quality and single-leg balance/control.', 'After bilateral pogos and single-leg balance are clean; before continuous single-leg contacts or lateral bounds.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Do not assign before bilateral pogos are clean. Hops too high or loud contacts mean regress dose.', 'Regress to single-leg balance hold or wall-supported calf pulses; progress to continuous single-leg pogos when hold-to-hop stays aligned.'),
  ('snap-down-to-stick', 'Snap-downs teach athletes to rapidly organize into an athletic landing position without the higher impact of dropping from a box. The Prehab Guys'' landing mechanics article emphasizes that landing quality requires strong brakes, lower-extremity strength, and core stability, and that landing mechanics should be assessed carefully because compensations can be subtle.', 'Belongs in landing_to_output (334) — low-impact landing-to-output bridge before snap-down rebound and drop progressions.', 'Before jumps, rebounds, depth drops, and tumbling landings; early landing-to-output bridge in elastic block.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Stick quality is the goal — not speed for speed''s sake with valgus or extra steps after landing.', 'Regress to tall-to-athletic freeze at slow speed; progress to snap-down to rebound when stick is clean for 2 seconds.'),
  ('snap-down-to-rebound', 'Snap-down to rebound introduces a quick transition from braking to propulsion. This is an early SSC bridge before depth drops and depth jumps. The key is that the athlete can land in alignment, absorb force quickly, and then rebound without collapsing. Plyometric training relies on rapid eccentric-to-concentric coupling, so the snap-down-to-rebound is a low-height way to teach that sequence before more stressful drop variations.', 'Belongs in landing_to_output (334) — SSC bridge after snap-down stick, before drop landing and depth rebound work.', 'After snap-down to stick is clean; bridges landing mechanics into reactive elastic output before drop rebounds.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Requires snap-down stick competency. Do not skip the snap or stay on ground too long before rebound.', 'Regress to snap-down to stick; progress to depth drop to rebound only when rebound is vertical, crisp, and final landing is controlled.'),
  ('drop-landing-to-stick', 'Drop landings train the athlete''s brakes: ankle, knee, hip, trunk, and foot control under impact. The Prehab Guys emphasize that landing mechanics require strong lower-extremity brakes and core stability, and that landing should be coached before progressing to more demanding jumping tasks.', 'Belongs in drop_landing (335) — force absorption drill after snap-down stick, before depth drop to rebound.', 'After snap-down landing is clean; before depth drop to rebound or hurdle hop series with impact.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Box height must stay low enough for quiet aligned landing — do not jump up before dropping or chase height over quality.', 'Regress to snap-down to stick or 4–8 inch step-down; raise box only when landing stays quiet and frozen.'),
  ('depth-drop-to-rebound', 'Depth drop to rebound introduces the athlete to a more reactive SSC demand: step off, absorb, and immediately reapply force. The Prehab Guys'' depth drop hop reference describes stepping off an elevated surface, absorbing the landing by bending the knee and hinging forward, then pushing into the ground and jumping vertically in one controlled continuous motion.', 'Belongs in drop_rebound (336) — advanced reactive drop after drop landing to stick; low box height mandatory.', 'Late in elastic rudiments block after drop landing to stick and snap-down to rebound; before hurdle hop series or jump power work.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Advanced compared with drop landing to stick. Do not use for beginners or when ground contact is long or loud.', 'Regress to drop landing to stick or snap-down to rebound; raise box only if contact time, alignment, and final stick remain excellent.'),
  ('hurdle-hop-series-low-hurdles', 'Hurdle hops create a repeated reactive jumping task with a clear external constraint: clear the hurdle and rebound into the next one. Sportsmith notes that hurdle constraints can simplify reactive jump instructions by keeping jump height demands consistent and focusing the athlete on fast elastic contacts. Just Fly Sports describes serial hurdle hops as combining the power of a depth jump with rhythm and coordination demands across multiple jumps, with athletes rebounding over hurdles in sequence.', 'Belongs in repeated_elastic_hop (337) — repeated elastic series after landing competency; low hurdles only until rhythm and clearance are consistent.', 'After pogos, snap-downs, and landing competency; late in elastic rudiments block before jump power work.', 'Elastic stiffness / plyometric rudiments belong in Output while the athlete is fresh — crisp contacts, short ground time, generous rest, quiet springy landings. Elastic drills should make the athlete springier, not tired. Do not use as conditioning finishers, high-volume bounce circuits, or fatigue work when contacts get loud or slow. Low hurdles only — not max-height tuck jumps. Stop when athlete clips hurdles or contacts get heavy.', 'Regress to line hops or cone hops; lower hurdle height and reduce count before adding speed or spacing.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Elastic rudiments cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'output_elastic_readiness',
  NULL,
  'Elastic Stiffness / Plyometric Rudiments without pre-fatigue',
  'Elastic Output requires crisp contacts, generous rest, and clean landings — drills should make the athlete springier, not tired.',
  'Output elastic cards express SSC stiffness through pogos, line hops, snap-downs, drop landings, depth rebounds, and low hurdle hop series.',
  'Plyometric rudiments load tendons, ankles, knees, and landing mechanics heavily. High volume, short rest, or poor landing quality turns Output into conditioning and raises injury risk.',
  'Use bilateral pogos before single-leg work, Snap-Down to Stick before rebound, drop landing before depth rebound, cap contacts, and stop when contacts get loud or landings fail.',
  'Do not program elastic drills after conditioning, with high contact volume, short rest, or as finishers when landing quality drops — regress dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
